  1→//! Compositional mock generation from behavior maps.
  2→//!
  3→//! When function A calls function B and B's [`BehaviorMap`] is available,
  4→//! this module builds an input-conditional decision tree that produces
  5→//! high-fidelity mocks: given the same arguments B received during
  6→//! exploration, the mock returns the same value (or throws the same error).
  7→//!
  8→//! The flat [`MockConfig`] format cycles through return values in order,
  9→//! ignoring what the caller actually passes. A [`MockDecisionTree`] instead
 10→//! matches each call's arguments against observed input patterns and picks
 11→//! the correct output, falling back to a default when no pattern matches.
 12→
 13→use serde::{Deserialize, Serialize};
 14→
 15→use crate::behavior::{Behavior, BehaviorMap};
 16→use crate::protocol::{MockBehavior, MockConfig};
 17→
 18→// ---------------------------------------------------------------------------
 19→// Pattern matching types
 20→// ---------------------------------------------------------------------------
 21→
 22→/// How to match a single argument value.
 23→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 24→#[serde(tag = "kind", rename_all = "snake_case")]
 25→pub enum PatternMatcher {
 26→    /// Exact JSON equality.
 27→    Eq { value: serde_json::Value },
 28→    /// Numeric range (inclusive on both ends).
 29→    Range { min: f64, max: f64 },
 30→    /// Match by JSON type name ("number", "string", "boolean", "null", "array", "object").
 31→    Type { type_name: String },
 32→    /// Match anything.
 33→    Any,
 34→}
 35→
 36→/// A condition on one argument of the mocked function.
 37→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 38→pub struct InputPattern {
 39→    /// Zero-based index of the argument to check.
 40→    pub arg_index: usize,
 41→    /// How to match the argument.
 42→    pub matcher: PatternMatcher,
 43→}
 44→
 45→/// A single branch of the decision tree: if all input patterns match,
 46→/// return `return_value` (or throw `error`).
 47→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 48→pub struct MockCondition {
 49→    /// Patterns that must all match for this condition to fire.
 50→    pub input_patterns: Vec<InputPattern>,
 51→    /// Value to return when the condition matches.
 52→    pub return_value: serde_json::Value,
 53→    /// If set, throw this error instead of returning.
 54→    pub error: Option<String>,
 55→}
 56→
 57→/// An input-conditional mock: an ordered list of conditions checked
 58→/// top-to-bottom, with a default for unmatched calls.
 59→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 60→pub struct MockDecisionTree {
 61→    /// The symbol this mock replaces.
 62→    pub symbol: String,
 63→    /// Ordered conditions — first match wins.
 64→    pub conditions: Vec<MockCondition>,
 65→    /// Value returned when no condition matches.
 66→    pub default_return: serde_json::Value,
 67→}
 68→
 69→// ---------------------------------------------------------------------------
 70→// Building decision trees from behavior maps
 71→// ---------------------------------------------------------------------------
 72→
 73→/// Build a [`MockDecisionTree`] from a [`BehaviorMap`].
 74→///
 75→/// Each behavior becomes a condition whose input patterns are exact-match
 76→/// on every argument, and whose output is the observed return value (or
 77→/// error). Behaviors that have neither a return value nor a thrown error
 78→/// are skipped.
 79→///
 80→/// Returns `None` if the behavior map has no usable behaviors.
 81→pub fn build_mock_from_behavior_map(behavior_map: &BehaviorMap) -> Option<MockDecisionTree> {
 82→    let mut conditions: Vec<MockCondition> = Vec::new();
 83→    let mut last_return = serde_json::Value::Null;
 84→
 85→    for behavior in &behavior_map.behaviors {
 86→        if let Some(condition) = behavior_to_condition(behavior) {
 87→            if condition.error.is_none() {
 88→                last_return = condition.return_value.clone();
 89→            }
 90→            conditions.push(condition);
 91→        }
 92→    }
 93→
 94→    if conditions.is_empty() {
 95→        return None;
 96→    }
 97→
 98→    Some(MockDecisionTree {
 99→        symbol: behavior_map.function_id.clone(),
100→        conditions,
101→        default_return: last_return,
102→    })
103→}
104→
105→/// Convert a single [`Behavior`] into a [`MockCondition`].
106→///
107→/// Returns `None` if the behavior has no return value and no thrown error.
108→fn behavior_to_condition(behavior: &Behavior) -> Option<MockCondition> {
109→    let has_return = behavior.return_value.is_some();
110→    let has_error = behavior.thrown_error.is_some();
111→
112→    if !has_return && !has_error {
113→        return None;
114→    }
115→
116→    let input_patterns: Vec<InputPattern> = behavior
117→        .input_args
118→        .iter()
119→        .enumerate()
120→        .map(|(i, arg)| InputPattern {
121→            arg_index: i,
122→            matcher: PatternMatcher::Eq {
123→                value: arg.clone(),
124→            },
125→        })
126→        .collect();
127→
128→    let return_value = behavior
129→        .return_value
130→        .clone()
131→        .unwrap_or(serde_json::Value::Null);
132→
133→    let error = behavior
134→        .thrown_error
135→        .as_ref()
136→        .map(|e| e.message.clone());
137→
138→    Some(MockCondition {
139→        input_patterns,
140→        return_value,
141→        error,
142→    })
143→}
144→
145→/// Check whether a set of arguments matches all input patterns in a condition.
146→pub fn matches_condition(args: &[serde_json::Value], condition: &MockCondition) -> bool {
147→    condition.input_patterns.iter().all(|pattern| {
148→        args.get(pattern.arg_index)
149→            .is_some_and(|arg| matches_pattern(arg, &pattern.matcher))
150→    })
151→}
152→
153→/// Check whether a single argument matches a pattern.
154→fn matches_pattern(value: &serde_json::Value, matcher: &PatternMatcher) -> bool {
155→    match matcher {
156→        PatternMatcher::Eq { value: expected } => value == expected,
157→        PatternMatcher::Range { min, max } => value
158→            .as_f64()
159→            .is_some_and(|n| n >= *min && n <= *max),
160→        PatternMatcher::Type { type_name } => json_type_name(value) == type_name.as_str(),
161→        PatternMatcher::Any => true,
162→    }
163→}
164→
165→/// Return a type name string for a JSON value.
166→fn json_type_name(value: &serde_json::Value) -> &'static str {
167→    match value {
168→        serde_json::Value::Null => "null",
169→        serde_json::Value::Bool(_) => "boolean",
170→        serde_json::Value::Number(_) => "number",
171→        serde_json::Value::String(_) => "string",
172→        serde_json::Value::Array(_) => "array",
173→        serde_json::Value::Object(_) => "object",
174→    }
175→}
176→
177→// ---------------------------------------------------------------------------
178→// Conversion to protocol MockConfig
179→// ---------------------------------------------------------------------------
180→
181→/// Convert a [`MockDecisionTree`] to the flat [`MockConfig`] protocol type.
182→///
183→/// The decision tree's conditions are flattened: each condition's return value
184→/// becomes an entry in `return_values` (error conditions produce `null`).
185→/// The decision tree metadata is stored in the return values so frontends
186→/// can reconstruct conditional behavior.
187→///
188→/// This is a lossy conversion — the flat format cannot fully represent
189→/// input-conditional logic. For frontends that support conditional mocks,
190→/// the tree should be sent directly (future protocol extension).
191→pub fn to_enhanced_mock_config(tree: &MockDecisionTree) -> MockConfig {
192→    let return_values: Vec<serde_json::Value> = tree
193→        .conditions
194→        .iter()
195→        .filter(|c| c.error.is_none())
196→        .map(|c| c.return_value.clone())
197→        .collect();
198→
199→    MockConfig {
200→        symbol: tree.symbol.clone(),
201→        return_values,
202→        should_track_calls: true,
203→        default_behavior: MockBehavior::RepeatLast,
204→    }
205→}
206→
207→/// Build a [`MockConfig`] from a [`BehaviorMap`], using the decision tree
208→/// when possible and falling back to the flat conversion otherwise.
209→pub fn mock_config_from_behavior_map(behavior_map: &BehaviorMap) -> MockConfig {
210→    match build_mock_from_behavior_map(behavior_map) {
211→        Some(tree) => to_enhanced_mock_config(&tree),
212→        None => behavior_map.to_mock_config(),
213→    }
214→}
