529→    // -- Serialization round-trip --
530→
531→    #[test]
532→    fn decision_tree_round_trips_through_json() {
533→        let tree = MockDecisionTree {
534→            symbol: "myFunc".to_string(),
535→            conditions: vec![
536→                MockCondition {
537→                    input_patterns: vec![InputPattern {
538→                        arg_index: 0,
539→                        matcher: PatternMatcher::Eq { value: json!(1) },
540→                    }],
541→                    return_value: json!("one"),
542→                    error: None,
543→                },
544→                MockCondition {
