2055→/// Mutate mock return values while preserving type contracts.
2056→///
2057→/// For each MockConfig/MockParam pair, applies [`mutate_value`] to each
2058→/// return value with probability `mutation_rate`. Output always has the
2059→/// same number of configs with the same symbols and vector lengths.
2060→pub fn mutate_mock_values(
2061→    configs: &[MockConfig],
2062→    mock_params: &[MockParam],
2063→    mutation_rate: f64,
2064→    dictionary: &[&str],
2065→    rng: &mut impl Rng,
2066→) -> Vec<MockConfig> {
2067→    configs
2068→        .iter()
2069→        .zip(mock_params.iter())
2070→        .map(|(config, mp)| {
2071→            let return_values = config
2072→                .return_values
2073→                .iter()
2074→                .map(|val| {
2075→                    if rng.random_range(0.0..1.0_f64) < mutation_rate {
2076→                        mutate_value(val, &mp.return_type, dictionary, rng)
2077→                    } else {
2078→                        val.clone()
2079→                    }
2080→                })
2081→                .collect();
2082→
2083→            MockConfig {
2084→                symbol: config.symbol.clone(),
2085→                return_values,
2086→                should_track_calls: config.should_track_calls,
2087→                default_behavior: config.default_behavior.clone(),
2088→            }
2089→        })
2090→        .collect()
2091→}
2092→
2093→/// Cross over two parent mock config vectors, preserving vector structure.
2094→///
2095→/// With probability `crossover_rate`, performs per-value crossover between
2096→/// matching return values. Both children have the same number of configs
2097→/// with the same symbols as the parents.
2098→pub fn crossover_mock_values(
2099→    parent_a: &[MockConfig],
2100→    parent_b: &[MockConfig],
2101→    mock_params: &[MockParam],
2102→    crossover_rate: f64,
2103→    rng: &mut impl Rng,
2104→) -> (Vec<MockConfig>, Vec<MockConfig>) {
2105→    let len = parent_a.len().min(parent_b.len()).min(mock_params.len());
2106→
2107→    if rng.random_range(0.0..1.0_f64) >= crossover_rate {
2108→        return (parent_a.to_vec(), parent_b.to_vec());
2109→    }
2110→
2111→    let mut child1 = Vec::with_capacity(len);
2112→    let mut child2 = Vec::with_capacity(len);
2113→
2114→    for i in 0..len {
2115→        let (rv1, rv2) = crossover_return_values(
2116→            &parent_a[i].return_values,
2117→            &parent_b[i].return_values,
2118→            &mock_params[i].return_type,
2119→            rng,
2120→        );
2121→
2122→        child1.push(MockConfig {
2123→            symbol: parent_a[i].symbol.clone(),
2124→            return_values: rv1,
2125→            should_track_calls: parent_a[i].should_track_calls,
2126→            default_behavior: parent_a[i].default_behavior.clone(),
2127→        });
2128→        child2.push(MockConfig {
2129→            symbol: parent_b[i].symbol.clone(),
2130→            return_values: rv2,
2131→            should_track_calls: parent_b[i].should_track_calls,
2132→            default_behavior: parent_b[i].default_behavior.clone(),
2133→        });
2134→    }
2135→
2136→    (child1, child2)
2137→}
2138→
2139→/// Cross over two return value vectors using per-element type-aware crossover.
2140→fn crossover_return_values(
2141→    a: &[Value],
2142→    b: &[Value],
2143→    typ: &TypeInfo,
2144→    rng: &mut impl Rng,
2145→) -> (Vec<Value>, Vec<Value>) {
2146→    let overlap = a.len().min(b.len());
2147→    let mut rv1 = Vec::with_capacity(a.len());
2148→    let mut rv2 = Vec::with_capacity(b.len());
2149→
2150→    for i in 0..overlap {
2151→        let (c1, c2) = crossover_value(&a[i], &b[i], typ, rng);
2152→        rv1.push(c1);
2153→        rv2.push(c2);
2154→    }
2155→
2156→    rv1.extend(a.iter().skip(overlap).cloned());
2157→    rv2.extend(b.iter().skip(overlap).cloned());
2158→
2159→    (rv1, rv2)
2160→}
